// BarcodeItem A single barcodes row in the barcode authority federation
// (feature #142, migration 0030_barcodes.sql). Each barcode is
// scoped to exactly one authority; `(authority_id, external_ref)`
// is UNIQUE among rows. Lifecycle: `active` → `scanned` (via
// POST /v1/scan) or `active`|`scanned` → `revoked` (terminal, via
// DELETE /v1/barcodes/{id}).
type BarcodeItem struct {
	// AuthorityId UUIDv7 of the barcode authority the barcode belongs to.
	AuthorityId openapi_types.UUID `json:"authority_id"`

	// CreatedAt ISO 8601 / RFC 3339 timestamp of row creation.
	CreatedAt time.Time `json:"created_at"`

	// ExternalRef The barcode string as printed / encoded on the ticket.
	// Unique within the owning authority.
	ExternalRef string `json:"external_ref"`

	// Id UUIDv7 primary key of the barcodes row.
	Id openapi_types.UUID `json:"id"`

	// ScannedAt UTC timestamp of the successful scan. `null` until the
	// barcode has been scanned.
	ScannedAt *time.Time `json:"scanned_at"`

	// Status Lifecycle status. `active` barcodes admit entry; `scanned`
	// marks a consumed barcode (double-scan protected); `revoked`
	// is terminal.
	Status BarcodeItemStatus `json:"status"`

	// TicketId Optional link to a platform tickets row. `null` for barcodes
	// originating from external platforms or guest lists.
	TicketId *openapi_types.UUID `json:"ticket_id"`

	// UpdatedAt ISO 8601 / RFC 3339 timestamp of last update.
	UpdatedAt time.Time `json:"updated_at"`
}

// BarcodeItemStatus Lifecycle status. `active` barcodes admit entry; `scanned`
// marks a consumed barcode (double-scan protected); `revoked`
// is terminal.
type BarcodeItemStatus string

// BindSessionSeatingRequest Request body for the seating-bind endpoint. Assigns the given
// seating_plan_version to the target session in an assigned-seats
// or hybrid admission mode, materializes one session_seats row per
// geometry seat, and applies the category → tier map. When
// `auto_create_tiers` is true, unmapped categories are provisioned
// as new ticket_tiers rows using the geometry category name /
// price_hint / currency_hint.
type BindSessionSeatingRequest struct {
	// AdmissionMode Admission mode to set on the session. GA sessions never reach this endpoint.
	AdmissionMode BindSessionSeatingRequestAdmissionMode `json:"admission_mode"`

	// AutoCreateTiers When true, categories without a mapping are provisioned as new tiers.
	AutoCreateTiers *bool `json:"auto_create_tiers,omitempty"`

	// CategoryTierMap Map of category index (stringified) → ticket_tiers UUID. Every
	// geometry category MUST have an entry unless `auto_create_tiers`
	// is true. A `null` value asks the server to auto-provision a
	// tier for that category.
	CategoryTierMap map[string]openapi_types.UUID `json:"category_tier_map"`

	// SeatingPlanVersionId UUIDv7 of the seating_plan_versions row to bind to the session.
	SeatingPlanVersionId openapi_types.UUID `json:"seating_plan_version_id"`
}

// BindSessionSeatingRequestAdmissionMode Admission mode to set on the session. GA sessions never reach this endpoint.
type BindSessionSeatingRequestAdmissionMode string

// BindSessionSeatingResponse Response envelope for the seating-bind endpoint. Echoes the
// updated session projection, the (possibly newly-locked) plan
// version, and a summary of the materialization step.
type BindSessionSeatingResponse struct {
	// CategoryTierMap Final category → tier UUID resolution, including any auto-created tiers.
	CategoryTierMap map[string]openapi_types.UUID `json:"category_tier_map"`

	// CreatedTierIds UUIDs of ticket_tiers rows auto-created for previously-unmapped categories.
	CreatedTierIds *[]openapi_types.UUID `json:"created_tier_ids,omitempty"`

	// MaterializedSeats Number of session_seats rows materialized in the bind transaction.
	MaterializedSeats int `json:"materialized_seats"`

	// Rebound True when the session already carried a binding and this call replaced it.
	Rebound bool `json:"rebound"`

	// SeatingPlanVersion Snapshot of the bound seating_plan_versions row (echoes locked_at, capacity, checksum).
	SeatingPlanVersion SeatingPlanVersion `json:"seating_plan_version"`

	// Session Projection of the updated session row.
	Session struct {
		// AdmissionMode Post-bind admission mode.
		AdmissionMode string `json:"admission_mode"`

		// CapacityTotal Recomputed session capacity (seated + standing).
		CapacityTotal int32 `json:"capacity_total"`

		// EventId UUIDv7 of the parent event.
		EventId openapi_types.UUID `json:"event_id"`

		// Id UUIDv7 of the session.
		Id openapi_types.UUID `json:"id"`

		// SeatStatusVersion Live session-scoped monotonic cursor for seat status.
		SeatStatusVersion int64 `json:"seat_status_version"`

		// SeatingPlanVersionId UUIDv7 of the bound plan version, when set.
		SeatingPlanVersionId *openapi_types.UUID `json:"seating_plan_version_id,omitempty"`
	} `json:"session"`
}

// CheckoutRecoverResponse Response body for `POST /v1/public/checkout/{checkout_token}/recover`
// (feature #320 WID-0c).  Returned when a fresh reservation was
// successfully created for the same seats/zones.
type CheckoutRecoverResponse struct {
	// CheckoutSession Canonical representation of a `checkout_sessions` row, returned by
	// every endpoint in the checkout session state machine implemented in
	// `apps/backend/internal/platform/httpserver/checkout.go`. Pricing
	// snapshot fields (`subtotal`, `discount`, `platform_fee`,
	// `provider_fee`, `tax`, `total`, `currency`, `promo_code_id`) are
	// populated once the session transitions out of `created` via
	// `POST /v1/checkout/{id}/confirm`. Payment fields
	// (`payment_intent_id`, `payment_provider`) are populated when the
	// session is completed via the paid path; the free path (total = 0)
	// leaves them `null`. Terminal-state timestamps are mutually
	// exclusive: exactly one of `completed_at`, `abandoned_at`,
	// `expired_at` is set when the session is terminal.
	CheckoutSession CheckoutSessionItem `json:"checkout_session"`

	// CheckoutToken The same opaque token that was supplied in the path (echoed back
	// for convenience so the widget does not need to re-parse the URL).
	CheckoutToken string `json:"checkout_token"`

	// ExpiresAt RFC 3339 UTC timestamp of the new reservation expiry.  The widget
	// MUST restart its countdown timer from this value.
	ExpiresAt time.Time `json:"expires_at"`
}

// CheckoutSessionEnvelope Top-level response envelope returned by every checkout-session
// endpoint. Wraps a single `CheckoutSessionItem` under the
// `checkout_session` key, matching the convention used by other
// single-resource fetches in this API.
type CheckoutSessionEnvelope struct {
	// CheckoutSession Canonical representation of a `checkout_sessions` row, returned by
	// every endpoint in the checkout session state machine implemented in
	// `apps/backend/internal/platform/httpserver/checkout.go`. Pricing
	// snapshot fields (`subtotal`, `discount`, `platform_fee`,
	// `provider_fee`, `tax`, `total`, `currency`, `promo_code_id`) are
	// populated once the session transitions out of `created` via
	// `POST /v1/checkout/{id}/confirm`. Payment fields
	// (`payment_intent_id`, `payment_provider`) are populated when the
	// session is completed via the paid path; the free path (total = 0)
	// leaves them `null`. Terminal-state timestamps are mutually
	// exclusive: exactly one of `completed_at`, `abandoned_at`,
	// `expired_at` is set when the session is terminal.
	CheckoutSession CheckoutSessionItem `json:"checkout_session"`
}

// CheckoutSessionItem Canonical representation of a `checkout_sessions` row, returned by
// every endpoint in the checkout session state machine implemented in
// `apps/backend/internal/platform/httpserver/checkout.go`. Pricing
// snapshot fields (`subtotal`, `discount`, `platform_fee`,
// `provider_fee`, `tax`, `total`, `currency`, `promo_code_id`) are
// populated once the session transitions out of `created` via
// `POST /v1/checkout/{id}/confirm`. Payment fields
// (`payment_intent_id`, `payment_provider`) are populated when the
// session is completed via the paid path; the free path (total = 0)
// leaves them `null`. Terminal-state timestamps are mutually
// exclusive: exactly one of `completed_at`, `abandoned_at`,
// `expired_at` is set when the session is terminal.
type CheckoutSessionItem struct {
	// AbandonedAt RFC3339 timestamp when the session reached `abandoned`.
	AbandonedAt *time.Time `json:"abandoned_at"`

	// ChannelId Sales channel the session was created in.
	ChannelId openapi_types.UUID `json:"channel_id"`

	// CompletedAt RFC3339 timestamp when the session reached `completed`.
	CompletedAt *time.Time `json:"completed_at"`

	// CreatedAt RFC3339 row-creation timestamp.
	CreatedAt time.Time `json:"created_at"`

	// Currency ISO 4217 currency code snapshot (`USD`, `EUR`, ...).
	Currency *string `json:"currency"`

	// Discount Pricing-snapshot discount, clamped to `[0, subtotal]`.
	Discount *int64 `json:"discount"`

	// ExpiredAt RFC3339 timestamp when the session was force-expired by the
	// reservation processor or TTL worker.
	ExpiredAt *time.Time `json:"expired_at"`

	// Id UUIDv7 of the checkout session row.
	Id openapi_types.UUID `json:"id"`

	// OrgId Organization that owns the session.
	OrgId openapi_types.UUID `json:"org_id"`

	// PaymentIntentId Provider-side payment intent identifier captured when the
	// session is completed via the paid path. `null` for free
	// checkouts (total = 0).
	PaymentIntentId *string `json:"payment_intent_id"`

	// PaymentProvider Payment provider name (e.g. `stripe`, `tinkoff`) captured at
	// completion. `null` for free checkouts.
	PaymentProvider *string `json:"payment_provider"`

	// PlatformFee Pricing-snapshot platform fee.
	PlatformFee *int64 `json:"platform_fee"`

	// PromoCodeId ID of the promo code applied at confirm time; `null` when
	// no promo was supplied or it failed validation.
	PromoCodeId *openapi_types.UUID `json:"promo_code_id"`

	// ProviderFee Pricing-snapshot provider fee.
	ProviderFee *int64 `json:"provider_fee"`

	// ReservationId Reservation the session wraps. The reservation must already
	// exist and be in `active` (or compatible) state. When the
	// reservation expires the checkout session is cascaded to
	// `expired` by `reservation_processor.go`.
	ReservationId openapi_types.UUID `json:"reservation_id"`

	// State Current state in the checkout state machine. Valid
	// transitions:
	// `created` → {`pricing_confirmed`, `abandoned`, `expired`};
	// `pricing_confirmed` → {`completed`, `payment_started`,
	// `abandoned`, `expired`};
	// `payment_started` → {`completed`, `manual_review`,
	// `abandoned`, `expired`};
	// `manual_review` → {`completed`, `abandoned`};
	// `completed`, `abandoned`, `expired` are terminal.
	State CheckoutSessionItemState `json:"state"`

	// Subtotal Pricing-snapshot `unit_price * quantity`, in minor currency
	// units. `null` until the session is confirmed.
	Subtotal *int64 `json:"subtotal"`

	// Tax Pricing-snapshot tax.
	Tax *int64 `json:"tax"`

	// Total Pricing-snapshot grand total:
	// `(subtotal - discount) + platform_fee + provider_fee + tax`.
	Total *int64 `json:"total"`

	// UpdatedAt RFC3339 last-update timestamp.
	UpdatedAt time.Time `json:"updated_at"`

	// UserId Authenticated buyer when known; `null` for anonymous /
	// guest checkouts. Set at session creation and immutable.
	UserId *openapi_types.UUID `json:"user_id"`
}

// CheckoutSessionItemState Current state in the checkout state machine. Valid
// transitions:
// `created` → {`pricing_confirmed`, `abandoned`, `expired`};
// `pricing_confirmed` → {`completed`, `payment_started`,
// `abandoned`, `expired`};
// `payment_started` → {`completed`, `manual_review`,
// `abandoned`, `expired`};
// `manual_review` → {`completed`, `abandoned`};
// `completed`, `abandoned`, `expired` are terminal.
type CheckoutSessionItemState string

